function initiateAccountRecovery(
  address smartWallet, address userSigningKey, uint256 extraTime
) external onlyOwnerOr(Role.OPERATOR) {
  require(smartWallet != address(0), "No smart wallet address provided.");
  require(userSigningKey != address(0), "No new user signing key provided.");

  // Set the timelock and emit a `TimelockInitiated` event.
  _setTimelock(
    this.recover.selector, abi.encode(smartWallet, userSigningKey), extraTime
  );
}

function pause(Role role) external onlyOwnerOr(Role.PAUSER) {
  RoleStatus storage storedRoleStatus = _roles[uint256(role)];
  require(!storedRoleStatus.paused, "Role in question is already paused.");
  storedRoleStatus.paused = true;
  emit RolePaused(role);
}

function _constructInitializationCalldata(
  address userSigningKey
) private pure returns (bytes memory initializationCalldata) {
  address[] memory keys = new address[](1);
  keys[0] = userSigningKey;

  uint8[] memory keyTypes = new uint8[](1);
  keyTypes[0] = uint8(3); // Dual key type

  // Get initialization calldata from initialize selector & arguments.
  initializationCalldata = abi.encodeWithSelector(
    _INITIALIZE_SELECTOR, 1, 1, keys, keyTypes
  );
}

constructor() public {
  DharmaKeyRingInitializer initializer;
  require(
    initializer.initialize.selector == _INITIALIZE_SELECTOR,
    "Incorrect initializer selector supplied."
  );

  require(
    _KEY_RING_INSTANCE_RUNTIME_HASH == keccak256(
      type(KeyRingUpgradeBeaconProxyV1).runtimeCode
    ),
    "Incorrect keyring runtime code hash supplied."
  );
}

constructor() public {
  DharmaSmartWalletImplementationV0Interface initializer;
  require(
    initializer.initialize.selector == _INITIALIZE_SELECTOR,
    "Incorrect initializer selector supplied."
  );

  require(
    _SMART_WALLET_INSTANCE_RUNTIME_HASH == keccak256(
      type(UpgradeBeaconProxyV1).runtimeCode
    ),
    "Incorrect smart wallet runtime code hash supplied."
  );
}

constructor() internal {
  TimelockerModifiersInterface modifiers;

  bytes4 targetModifyInterval = modifiers.modifyTimelockInterval.selector;
  require(
    _MODIFY_TIMELOCK_INTERVAL_SELECTOR == targetModifyInterval,
    "Incorrect modify timelock interval selector supplied."
  );

  bytes4 targetModifyExpiration = modifiers.modifyTimelockExpiration.selector;
  require(
    _MODIFY_TIMELOCK_EXPIRATION_SELECTOR == targetModifyExpiration,
    "Incorrect modify timelock expiration selector supplied."
  );
}

constructor() public {
  // Set the transaction submitter as the initial owner of this contract.
  _owner = tx.origin;
  emit OwnershipTransferred(address(0), tx.origin);

  // Ensure the upgrade beacon envoy has the expected runtime code.
  address envoy = address(_UPGRADE_BEACON_ENVOY);
  bytes32 envoyCodeHash;
  assembly { envoyCodeHash := extcodehash(envoy)}
  require(
    envoyCodeHash == bytes32(
      0x7332d06692fd32b21bdd8b8b7a0a3f0de5cf549668cbc4498fc6cfaa453f1176
    ),
    "Upgrade Beacon Envoy runtime code is incorrect."
  );
}

function _addOwners(address[] memory newOwners_) private {
    AMultiOwnableStorage storage $ = _getAMultiOwnableStorage();

    for (uint256 i = 0; i < newOwners_.length; ++i) {
        $.owners.add(newOwners_[i]);
    }

    if ($.owners.contains(address(0))) revert InvalidOwner();

    emit OwnersAdded(newOwners_);
}

function _removeOwners(address[] memory oldOwners_) private {
    AMultiOwnableStorage storage $ = _getAMultiOwnableStorage();

    for (uint256 i = 0; i < oldOwners_.length; ++i) {
        $.owners.remove(oldOwners_[i]);
    }

    emit OwnersRemoved(oldOwners_);
}

function revokeRoles(
    address from_,
    string[] memory rolesToRevoke_
) public virtual override onlyPermission(RBAC_RESOURCE, DELETE_PERMISSION) {
    if (rolesToRevoke_.length == 0) revert EmptyRoles();

    _revokeRoles(from_, rolesToRevoke_);
}

function validateUserOp(
    PackedUserOperation calldata userOp_,
    bytes32 userOpHash_,
    uint256 missingAccountFunds_
) external virtual returns (uint256 validationData_) {
    _onlyEntryPoint();

    validationData_ = _validateSignature(userOp_, userOpHash_);

    _validateNonce(userOp_.nonce);

    _payPrefund(missingAccountFunds_);
}

function _execute(
    bytes32,
    bytes calldata,
    Call[] calldata calls_,
    bytes calldata
) internal virtual override {
    if (
        msg.sender != address(this) &&
        msg.sender != trustedExecutor() &&
        msg.sender != entryPoint()
    ) {
        revert InvalidExecutor(msg.sender);
    }

    _execute(calls_, bytes32(0));
}

function _addSigners(address[] memory signers_) internal virtual {
    if (signers_.length == 0) revert InvalidSigners();

    ABridgeStorage storage $ = _getABridgeStorage();

    for (uint256 i = 0; i < signers_.length; ++i) {
        if (signers_[i] == address(0)) revert InvalidSigner(signers_[i]);

        $.signers.add(signers_[i]);
    }
}

function _removeSigners(address[] memory signers_) internal virtual {
    if (signers_.length == 0) revert InvalidSigners();

    ABridgeStorage storage $ = _getABridgeStorage();

    for (uint256 i = 0; i < signers_.length; ++i) {
        $.signers.remove(signers_[i]);
    }
}

function execute(bytes calldata batch_) external payable nonReentrant {
    (address[] memory targets_, uint256[] memory values_, bytes[] memory data_) = abi.decode(
        batch_,
        (address[], uint256[], bytes[])
    );

    for (uint256 i = 0; i < targets_.length; ++i) {
        if (data_[i].length > 0) {
            targets_[i].functionCallWithValue(data_[i], values_[i]);
        } else {
            payable(targets_[i]).sendValue(values_[i]);
        }
    }
}

function _addFacet(address facet_, bytes4[] memory selectors_) internal virtual {
    _checkIfFacetIsValid(facet_, selectors_);

    DStorage storage _ds = _getDiamondStorage();

    for (uint256 i = 0; i < selectors_.length; ++i) {
        if (_ds.selectorToFacet[selectors_[i]] != address(0))
            revert SelectorAlreadyAdded(_ds.selectorToFacet[selectors_[i]], selectors_[i]);

        _ds.selectorToFacet[selectors_[i]] = facet_;
        _ds.facetToSelectors[facet_].add(bytes32(selectors_[i]));
    }

    _ds.facets.add(facet_);
}

function modexpU256(
    call512 call_,
    uint512 b_,
    uint256 e_,
    uint512 m_
) internal view returns (uint512 r_) {
    unchecked {
        r_ = uint512.wrap(_allocate(_UINT512_ALLOCATION));

        _modexpU256(call_, b_, e_, m_, r_);
    }
}

function intoUint40(SD1x18 x) pure returns (uint40 result) {
    int64 xInt = SD1x18.unwrap(x);
    if (xInt < 0) {
        revert CastingErrors.PRBMath_SD1x18_ToUint40_Underflow(x);
    }
    if (xInt > int64(uint64(Common.MAX_UINT40))) {
        revert CastingErrors.PRBMath_SD1x18_ToUint40_Overflow(x);
    }
    result = uint40(uint64(xInt));
}

function intoUint40(SD21x18 x) pure returns (uint40 result) {
    int128 xInt = SD21x18.unwrap(x);
    if (xInt < 0) {
        revert CastingErrors.PRBMath_SD21x18_ToUint40_Underflow(x);
    }
    if (xInt > int128(uint128(Common.MAX_UINT40))) {
        revert CastingErrors.PRBMath_SD21x18_ToUint40_Overflow(x);
    }
    result = uint40(uint128(xInt));
}

function intoSD1x18(SD59x18 x) pure returns (SD1x18 result) {
    int256 xInt = SD59x18.unwrap(x);
    if (xInt < uMIN_SD1x18) {
        revert CastingErrors.PRBMath_SD59x18_IntoSD1x18_Underflow(x);
    }
    if (xInt > uMAX_SD1x18) {
        revert CastingErrors.PRBMath_SD59x18_IntoSD1x18_Overflow(x);
    }
    result = SD1x18.wrap(int64(xInt));
}

function intoSD21x18(SD59x18 x) pure returns (SD21x18 result) {
    int256 xInt = SD59x18.unwrap(x);
    if (xInt < uMIN_SD21x18) {
        revert CastingErrors.PRBMath_SD59x18_IntoSD21x18_Underflow(x);
    }
    if (xInt > uMAX_SD21x18) {
        revert CastingErrors.PRBMath_SD59x18_IntoSD21x18_Overflow(x);
    }
    result = SD21x18.wrap(int128(xInt));
}

function intoUD2x18(SD59x18 x) pure returns (UD2x18 result) {
    int256 xInt = SD59x18.unwrap(x);
    if (xInt < 0) {
        revert CastingErrors.PRBMath_SD59x18_IntoUD2x18_Underflow(x);
    }
    if (xInt > int256(uint256(uMAX_UD2x18))) {
        revert CastingErrors.PRBMath_SD59x18_IntoUD2x18_Overflow(x);
    }
    result = UD2x18.wrap(uint64(uint256(xInt)));
}

function intoUD21x18(SD59x18 x) pure returns (UD21x18 result) {
    int256 xInt = SD59x18.unwrap(x);
    if (xInt < 0) {
        revert CastingErrors.PRBMath_SD59x18_IntoUD21x18_Underflow(x);
    }
    if (xInt > int256(uint256(uMAX_UD21x18))) {
        revert CastingErrors.PRBMath_SD59x18_IntoUD21x18_Overflow(x);
    }
    result = UD21x18.wrap(uint128(uint256(xInt)));
}

function convert(int256 x) pure returns (SD59x18 result) {
    if (x < uMIN_SD59x18 / uUNIT) {
        revert PRBMath_SD59x18_Convert_Underflow(x);
    }
    if (x > uMAX_SD59x18 / uUNIT) {
        revert PRBMath_SD59x18_Convert_Overflow(x);
    }
    unchecked {
        result = SD59x18.wrap(x * uUNIT);
    }
}

function intoSD1x18(UD60x18 x) pure returns (SD1x18 result) {
    uint256 xUint = UD60x18.unwrap(x);
    if (xUint > uint256(int256(uMAX_SD1x18))) {
        revert CastingErrors.PRBMath_UD60x18_IntoSD1x18_Overflow(x);
    }
    result = SD1x18.wrap(int64(uint64(xUint)));
}

function exp(UD60x18 x) pure returns (UD60x18 result) {
    uint256 xUint = x.unwrap();

    // This check prevents values greater than 192e18 from being passed to {exp2}.
    if (xUint > uEXP_MAX_INPUT) {
        revert Errors.PRBMath_UD60x18_Exp_InputTooBig(x);
    }

    unchecked {
        // Inline the fixed-point multiplication to save gas.
        uint256 doubleUnitProduct = xUint * uLOG2_E;
        result = exp2(wrap(doubleUnitProduct / uUNIT));
    }
}

function floor(UD60x18 x) pure returns (UD60x18 result) {
    assembly ("memory-safe") {
        // Equivalent to `x % UNIT`.
        let remainder := mod(x, uUNIT)

        // Equivalent to `x - ((remainder > 0) ? remainder : 0)`.
        result := sub(x, mul(remainder, gt(remainder, 0)))
    }
}

function ln(UD60x18 x) pure returns (UD60x18 result) {
    unchecked {
        // Inline the fixed-point multiplication to save gas. This is overflow-safe because the maximum value that
        // {log2} can return is ~196_205294292027477728.
        result = wrap(log2(x).unwrap() * uUNIT / uLOG2_E);
    }
}

function sqrt(UD60x18 x) pure returns (UD60x18 result) {
    uint256 xUint = x.unwrap();

    unchecked {
        if (xUint > uMAX_UD60x18 / uUNIT) {
            revert Errors.PRBMath_UD60x18_Sqrt_Overflow(x);
        }
        // Multiply x by `UNIT` to account for the factor of `UNIT` picked up when multiplying two UD60x18 numbers.
        // In this case, the two numbers are both the square root.
        result = wrap(Common.sqrt(xUint * uUNIT));
    }
}

function hash(ISignatureTransfer.PermitTransferFrom memory permit) internal view returns (bytes32) {
    bytes32 tokenPermissionsHash = _hashTokenPermissions(permit.permitted);
    return keccak256(
        abi.encode(_PERMIT_TRANSFER_FROM_TYPEHASH, tokenPermissionsHash, msg.sender, permit.nonce, permit.deadline)
    );
}
